	"github.com/volcano-sh/agentcube/pkg/router"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

func main() {
	port := flag.String("port", "8080", "HTTP server port")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS certificate path")
	tlsKey := flag.String("tls-key", "", "TLS key path")
	debug := flag.Bool("debug", false, "Enable debug mode")
	maxConcurrent := flag.Int("max-concurrent-requests", 1000, "Maximum concurrent requests")

	klog.InitFlags(flag.Parse())
	flag.Parse()

	cfg := &router.Config{
		Port:                  *port,
		Debug:                 *debug,
		EnableTLS:             *enableTLS,
		TLSCert:               *tlsCert,
		TLSKey:                *tlsKey,
		MaxConcurrentRequests: *maxConcurrent,
	}

	storeClient := store.Storage()

	sessionManager, err := router.NewSessionManager(storeClient)
	if err != nil {
		klog.Exitf("Failed to create session manager: %v", err)
	}

	server, err := router.NewServer(cfg, storeClient, sessionManager)
	if err != nil {
		klog.Exitf("Failed to create server: %v", err)
	}

	errCh := make(chan error, 1)
	go func() {
		errCh <- server.Start()
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	select {
	case err := <-errCh:
		klog.Exitf("Server error: %v", err)
	case <-sigCh:
		klog.Info("Shutting down server...")
		if err := server.Shutdown(nil); err != nil {
			klog.Errorf("Server shutdown error: %v", err)
		}
	}
}

