)

func main() {
	port := flag.String("port", "8080", "HTTP server port")
	workspace := flag.String("workspace", "", "Workspace root directory")

	klog.InitFlags(flag.Parse())
	flag.Parse()

	if *workspace == "" {
		cwd, err := os.Getwd()
		if err != nil {
			klog.Exitf("Failed to get current working directory: %v", err)
		}
		*workspace = cwd
	}

	cfg := &picod.Config{
		Port:     *port,
		Workspace: *workspace,
	}

	if err := picod.NewServer(cfg); err != nil {
		klog.Exitf("Failed to create server: %v", err)
	}

	klog.Infof("Starting PicoD on port %s with workspace %s", *port, *workspace)
	if err := picod.Start(); err != nil {
		klog.Exitf("Server error: %v", err)
	}
}

package picod

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"k8s.io/klog/v2"
)

var (
	serverInstance *http.Server
	startTime      = time.Now()
	config         *Config
	authManager    *AuthManager
)

type Config struct {
	Port              string
	Workspace         string
	AuthPublicKeyPEM  string
	MaxBodySize       int64
}

func NewServer(cfg *Config) error {
	if cfg.AuthPublicKeyPEM == "" {
		klog.Exit("PICOD_AUTH_PUBLIC_KEY is required")
	}

	publicKey, err := jwt.ParseRSAPublicKeyFromPEM([]byte(cfg.AuthPublicKeyPEM))
	if err != nil {
		klog.Exitf("Failed to parse public key: %v", err)
	}

	authManager = &AuthManager{publicKey: publicKey}
	config = cfg

	engine := gin.New()
	engine.Use(gin.Recovery())
	engine.Use(gin.Logger())

	engine.GET("/health", handleHealth)

	api := engine.Group("/api")
	api.Use(authManager.AuthMiddleware())
	{
		api.POST("/execute", handleExecute)
		api.POST("/files", handleFiles)
		api.GET("/files", handleListFiles)
		api.GET("/files/*path", handleDownloadFile)
	}

	serverInstance = &http.Server{
		Addr:              ":" + cfg.Port,
		Handler:           engine,
		ReadHeaderTimeout: 10 * time.Second,
	}

	return nil
}

func Start() error {
	return serverInstance.ListenAndServe()
}

